import React, { useEffect, useMemo, useState } from 'react';
import { Link } from 'react-router-dom';
import './Hero.css';

const MASCOT_IMAGE = 'https://www.genspark.ai/api/files/s/mg0kVaWB';

const statItems = [
  { label: '오늘의 체크인', value: '1.2만+', tone: 'purple' },
  { label: '누적 대화 세션', value: '8.4만+', tone: 'blue' },
  { label: '감정 리포트 생성', value: '3.1만+', tone: 'mint' },
];

function SendIcon() {
  return (
    <svg viewBox="0 0 24 24" aria-hidden="true">
      <path
        d="M4 11.5L19 4l-3.8 16-4.1-5-4.9-1.1L4 11.5z"
        fill="none"
        stroke="currentColor"
        strokeWidth="1.8"
        strokeLinejoin="round"
      />
    </svg>
  );
}

export default function Hero() {
  const [scrollState, setScrollState] = useState('idle');
  const [demoInput, setDemoInput] = useState('');

  useEffect(() => {
    const onScroll = () => {
      const y = window.scrollY || 0;

      if (y < 80) setScrollState('idle');
      else if (y < 320) setScrollState('wave');
      else setScrollState('react');
    };

    onScroll();
    window.addEventListener('scroll', onScroll, { passive: true });
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  const heroDemo = useMemo(() => {
    if (scrollState === 'wave') {
      return {
        bubble: '앗, 지금 둘러보고 있네요. 반가워요. 오늘 기분을 한마디로 말해볼래요?',
        options: ['조금 피곤해요', '편하게 얘기하고 싶어요'],
        chip: '반갑게 먼저 인사 중',
      };
    }

    if (scrollState === 'react') {
      return {
        bubble: '좋아요. 아래 기능도 같이 보면 더 잘 맞는 흐름을 찾을 수 있어요. 지금 가장 가까운 감정은 뭔가요?',
        options: ['생각이 많아요', '조금 위로받고 싶어요'],
        chip: '스크롤 반응 중',
      };
    }

    return {
      bubble: '오늘도 오래 버텼네요. 많이 애쓴 하루였어요. 지금 제일 무거운 감정은 어떤 건가요?',
      options: ['피곤함이 커요', '마음이 답답해요'],
      chip: '차분하고 따뜻한 공감형',
    };
  }, [scrollState]);

  return (
    <section className="cutehero-section">
      <div className="cutehero-bg cutehero-bg--one" />
      <div className="cutehero-bg cutehero-bg--two" />
      <div className="cutehero-bg cutehero-bg--three" />

      <div className="cutehero-container">
        <div className="cutehero-grid">
          <div className="cutehero-copy">
            <span className="cutehero-kicker">마음친구 스타일 버추얼 케어</span>

            <h1>
              먼저 다가가는
              <br />
              <strong>AI 친구</strong>
            </h1>

            <p>
              당신의 마음을 먼저 알아채는 상담 파트너처럼,
              <br />
              토끼와 고양이 캐릭터가 서비스 전체에서 다정하게 안내해줘요.
            </p>

            <div className="cutehero-actions">
              <Link to="/chat" className="cutehero-btn cutehero-btn--primary">
                캐릭터와 대화 시작하기
              </Link>
              <Link to="/signup" className="cutehero-btn cutehero-btn--ghost">
                무료로 시작하기
              </Link>
            </div>

            <div className="cutehero-stats">
              {statItems.map((item) => (
                <div
                  key={item.label}
                  className={`cutehero-stat-card cutehero-stat-card--${item.tone}`}
                >
                  <span>{item.label}</span>
                  <strong>{item.value}</strong>
                </div>
              ))}
            </div>
          </div>

          <div className={`cutehero-visual cutehero-visual--${scrollState}`}>
            <div className="cutehero-browser-card">
              <div className="cutehero-browser-bar">
                <div className="cutehero-browser-dots">
                  <span />
                  <span />
                  <span />
                </div>
                <div className="cutehero-browser-address">maumchingu.com</div>
              </div>

              <div className="cutehero-browser-body">
                <div className="cutehero-preview-left">
                  <div className="cutehero-preview-badge">하루 · 감정 케어 시작</div>
                  <h3>
                    토끼와 고양이가
                    <br />
                    먼저 말을 걸어주는 홈
                  </h3>
                  <p>
                    텍스트 카드가 아니라 캐릭터 중심으로 말풍선, 선택지,
                    입력창이 함께 보이도록 구성했어요.
                  </p>
                </div>

                <div className={`cutehero-preview-right cutehero-preview-right--${scrollState}`}>
                  <div className="cutehero-image-stage">
                    <div className="cutehero-image-glow cutehero-image-glow--one" />
                    <div className="cutehero-image-glow cutehero-image-glow--two" />
                    <div className="cutehero-image-floor" />

                    <div className="cutehero-image-wrap">
